var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"벌써 떠날 시기가 왔나보네요......","JPN":"もうお別れする時期がきたようですね……","ENG":"So, it's already time for us to leave.","TWN":"看來已經到離開的時候了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"괜찮습니다. 저희 오피셜 서포트는 기간제 파견직을 전제로 움직이니까요.","JPN":"大丈夫です。オフィシャルサポートは、期間限定の派遣を前提に動いていますから。","ENG":"It's okay. We the members of the Official Support are basically dispatch employees.","TWN":"沒關係，我們官方支援小隊是以定期派遣為前提活動的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"다른 데 가도 천덕꾸러기 취급이나 당하겠지만...... 종신계약이요?","JPN":"他のところに行っても、邪魔者扱いされるだけでしょうが……\\nえ、終身契約ですか？","ENG":"We'll be treated like a nuisance in other companies but—a lifetime contract?","TWN":"即使去別的地方也會被排擠……終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아이리나 캐시도 아니고, 저랑? 그렇지만 사장님 회사는 충분히 성장했는데......?","JPN":"アイリとかキャシーじゃなくて、私と？\\nでも、社長の会社は十分成長しているのに……？","ENG":"Neither Irie nor Cathy, but ME?! But hasn't your company grown big enough?","TWN":"不是艾莉，也不是凱西，而是和我？但是老闆的公司已經得到足夠的成長了吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"......회사가 아니라, 제가 성장하는 걸 더 보고 싶으시다고요?","JPN":"……会社ではなく、私が成長するのを見たいということですか？","ENG":"You want to see me grow now?","TWN":"……您說不是公司，而是想看我繼續成長嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그건...... 그건 완전......","JPN":"それは……それはもう……","ENG":"That's... That's totally...","TWN":"這……這完全……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아니. 이번이 아니면 기회가 없으니 솔직하게 말하겠습니다.","JPN":"いいえ、今じゃないともう機会がないので、率直に言わせていただきます。","ENG":"Well, I might not have another chance like this, so let me be honest.","TWN":"不，這次不說就再沒機會了，我就坦率地和您說吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"저도 마찬가지에요! 더 많이 배우고, 더 많은 경험을 쌓고 싶습니다! 그래서 두 사람에게 부끄럽지 않은, 훌륭한 소대장이 되고 싶어요!","JPN":"私の気持ちも同じです！もっと勉強して、もっと経験を積みたいです！\\nそして二人に恥じない、立派な小隊長になりたいです！","ENG":"I feel the same way! I want to learn and experience more, so I can be a great commander to the other two!","TWN":"我也一樣！我也多加學習，累積更多的經驗！我想成為不讓那兩個人感到丟臉的優秀小隊長！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"......가능하면, 사장님과 함께요.","JPN":"……できれば、社長と一緒に。","ENG":"With you, if that's possible.","TWN":"……如果可以的話，我也想和老闆在一起。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그러니까, 조금만 더 욕심을 부려도...... 괜찮겠죠?","JPN":"だから、もう少し欲張っても……大丈夫ですね？","ENG":"So... I hope you don't mind my being a little bit selfish.","TWN":"所以，我稍微貪心一點……應該沒關係吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};